#!/usr/bin/env dotnet-script
#r "nuget: System.Reflection, 4.3.0"

using System;
using System.Reflection;
using System.Linq;

string[] dllPaths = new[]
{
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.4.0/lib/net10.0/Microsoft.Agents.AI.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.3.0/lib/net10.0/Microsoft.Extensions.AI.OpenAI.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.2/lib/net10.0/Microsoft.Extensions.AI.dll"
};

foreach (var dllPath in dllPaths)
{
    if (!File.Exists(dllPath))
    {
        Console.WriteLine($"\n❌ NOT FOUND: {dllPath}\n");
        continue;
    }

    Console.WriteLine($"\n{'='*80}");
    Console.WriteLine($"📦 DLL: {Path.GetFileName(dllPath)}");
    Console.WriteLine($"{'='*80}");

    try
    {
        var asm = Assembly.LoadFrom(dllPath);
        var types = asm.GetExportedTypes().OrderBy(t => t.FullName).ToList();

        Console.WriteLine($"✓ Loaded. Exported Types: {types.Count}\n");

        foreach (var t in types)
        {
            // Filter to relevant namespaces only
            if (!t.Namespace?.Contains("Microsoft") ?? false)
                continue;

            Console.WriteLine($"\n{'─'*80}");
            Console.WriteLine($"📋 {t.FullName}");
            Console.WriteLine($"{'─'*80}");

            // Base class
            if (t.BaseType != null && t.BaseType != typeof(object))
                Console.WriteLine($"  Base: {t.BaseType.FullName}");

            // Interfaces
            var ifaces = t.GetInterfaces();
            if (ifaces.Length > 0)
                Console.WriteLine($"  Interfaces: {string.Join(", ", ifaces.Select(i => i.FullName))}");

            // Constructors
            var ctors = t.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
            if (ctors.Length > 0)
            {
                Console.WriteLine($"\n  Constructors:");
                foreach (var c in ctors)
                {
                    var args = string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"    • ctor({args})");
                }
            }

            // Methods (public instance + static)
            var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                .Where(m => !m.IsSpecialName)
                .OrderBy(m => m.Name)
                .ToList();

            if (methods.Count > 0)
            {
                Console.WriteLine($"\n  Methods:");
                foreach (var m in methods)
                {
                    var args = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    var isStatic = m.IsStatic ? "static " : "";
                    Console.WriteLine($"    • {isStatic}{m.ReturnType.Name} {m.Name}({args})");
                }
            }

            // Properties
            var props = t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
            if (props.Length > 0)
            {
                Console.WriteLine($"\n  Properties:");
                foreach (var p in props)
                {
                    var accessor = "";
                    if (p.CanRead) accessor += "get;";
                    if (p.CanWrite) accessor += " set;";
                    Console.WriteLine($"    • {p.PropertyType.Name} {p.Name} {{ {accessor} }}");
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"❌ Error loading assembly: {ex.Message}");
        Console.WriteLine($"   {ex.InnerException?.Message}");
    }
}

Console.WriteLine($"\n{'='*80}\n✅ Done\n");

